// API Gateway with Custom Plugin Loading
// gateway.js

const http = require('http');
const https = require('https');
const url = require('url');
const fs = require('fs');
const path = require('path');
const { EventEmitter } = require('events');

// ============================================
// Plugin Manager
// ============================================
class PluginManager extends EventEmitter {
  constructor() {
    super();
    this.plugins = new Map();
    this.hooks = {
      onRequest: [],
      onResponse: [],
      onError: [],
      onStartup: [],
      onShutdown: []
    };
  }

  // Load plugin from a file path using require()
  loadPluginFromFile(pluginPath) {
    const resolvedPath = path.resolve(pluginPath);
    if (!fs.existsSync(resolvedPath)) {
      throw new Error(`Plugin file not found: ${resolvedPath}`);
    }

    // Clear require cache for hot-reloading support
    delete require.cache[require.resolve(resolvedPath)];

    const plugin = require(resolvedPath);
    this.registerPlugin(plugin);
    console.log(`[PluginManager] Loaded plugin from file: ${resolvedPath}`);
    return plugin;
  }

  // Load plugin from inline code string using eval()
  loadPluginFromCode(code, pluginName = 'inline-plugin') {
    // WARNING: eval() is used intentionally here for dynamic plugin loading.
    // In production, ensure plugin code comes from trusted sources only.
    const moduleExports = {};
    const moduleObj = { exports: moduleExports };

    // Create a sandboxed-ish context for the plugin code
    const wrappedCode = `
      (function(module, exports, require, __filename, __dirname) {
        ${code}
      })(moduleObj, moduleExports, require, "${pluginName}", "${path.dirname(pluginName)}");
    `;

    eval(wrappedCode);

    const plugin = moduleObj.exports;
    if (!plugin.name) {
      plugin.name = pluginName;
    }
    this.registerPlugin(plugin);
    console.log(`[PluginManager] Loaded plugin from code: ${plugin.name}`);
    return plugin;
  }

  // Load plugin from environment variable
  loadPluginFromEnv(envVarName) {
    const value = process.env[envVarName];
    if (!value) {
      throw new Error(`Environment variable ${envVarName} is not set`);
    }

    // Check if the env var contains a file path or inline code
    if (value.endsWith('.js') || value.startsWith('/') || value.startsWith('./')) {
      return this.loadPluginFromFile(value);
    } else {
      return this.loadPluginFromCode(value, `env:${envVarName}`);
    }
  }

  // Register a plugin object
  registerPlugin(plugin) {
    if (!plugin.name) {
      throw new Error('Plugin must have a "name" property');
    }

    if (this.plugins.has(plugin.name)) {
      console.warn(`[PluginManager] Replacing existing plugin: ${plugin.name}`);
    }

    this.plugins.set(plugin.name, plugin);

    // Register hooks
    for (const hookName of Object.keys(this.hooks)) {
      if (typeof plugin[hookName] === 'function') {
        this.hooks[hookName].push({
          pluginName: plugin.name,
          handler: plugin[hookName].bind(plugin),
          priority: plugin.priority || 0
        });
        // Sort hooks by priority (higher priority runs first)
        this.hooks[hookName].sort((a, b) => b.priority - a.priority);
      }
    }

    // Call plugin init if available
    if (typeof plugin.init === 'function') {
      plugin.init(this);
    }

    this.emit('pluginLoaded', plugin.name);
  }

  // Unregister a plugin
  unregisterPlugin(pluginName) {
    if (!this.plugins.has(pluginName)) {
      return false;
    }

    // Remove hooks
    for (const hookName of Object.keys(this.hooks)) {
      this.hooks[hookName] = this.hooks[hookName].filter(
        h => h.pluginName !== pluginName
      );
    }

    const plugin = this.plugins.get(pluginName);
    if (typeof plugin.destroy === 'function') {
      plugin.destroy();
    }

    this.plugins.delete(pluginName);
    this.emit('pluginUnloaded', pluginName);
    console.log(`[PluginManager] Unregistered plugin: ${pluginName}`);
    return true;
  }

  // Execute hooks in sequence
  async executeHook(hookName, context) {
    const hooks = this.hooks[hookName] || [];
    for (const hook of hooks) {
      try {
        const result = await hook.handler(context);
        if (result === false) {
          // Plugin signals to stop the chain
          context._stopped = true;
          break;
        }
      } catch (err) {
        console.error(`[PluginManager] Error in plugin "${hook.pluginName}" hook "${hookName}":`, err.message);
        this.emit('pluginError', { pluginName: hook.pluginName, hookName, error: err });
        if (hookName !== 'onError') {
          // Propagate to error hooks
          await this.executeHook('onError', { ...context, error: err, sourcePlugin: hook.pluginName });
        }
      }
    }
    return context;
  }

  listPlugins() {
    const list = [];
    for (const [name, plugin] of this.plugins) {
      list.push({
        name,
        version: plugin.version || 'unknown',
        priority: plugin.priority || 0,
        hooks: Object.keys(this.hooks).filter(h =>
          this.hooks[h].some(hook => hook.pluginName === name)
        )
      });
    }
    return list;
  }
}

// ============================================
// Gateway Context (passed through plugin chain)
// ============================================
class GatewayContext {
  constructor(req, res) {
    this.req = req;
    this.res = res;
    this.requestId = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    this.startTime = Date.now();
    this.metadata = {};
    this.state = {};
    this._stopped = false;
    this._responseSent = false;

    // Parse URL
    this.parsedUrl = url.parse(req.url, true);
    this.path = this.parsedUrl.pathname;
    this.query = this.parsedUrl.query;
    this.method = req.method;
    this.headers = { ...req.headers };
    this.body = null;

    // Response modifications
    this.responseHeaders = {};
    this.responseStatusCode = null;
    this.responseBody = null;

    // Upstream target
    this.upstream = null;
    this.upstreamResponse = null;
  }

  // Set upstream target
  setUpstream(target) {
    this.upstream = target;
  }

  // Set response
  setResponse(statusCode, body, headers = {}) {
    this.responseStatusCode = statusCode;
    this.responseBody = body;
    this.responseHeaders = { ...this.responseHeaders, ...headers };
  }

  // Add response header
  addResponseHeader(key, value) {
    this.responseHeaders[key] = value;
  }

  // Send the response
  sendResponse() {
    if (this._responseSent) return;
    this._responseSent = true;

    const statusCode = this.responseStatusCode || 200;
    const headers = {
      'X-Request-Id': this.requestId,
      'X-Response-Time': `${Date.now() - this.startTime}ms`,
      ...this.responseHeaders
    };

    this.res.writeHead(statusCode, headers);

    if (this.responseBody !== null && this.responseBody !== undefined) {
      const body = typeof this.responseBody === 'object'
        ? JSON.stringify(this.responseBody)
        : String(this.responseBody);
      this.res.end(body);
    } else {
      this.res.end();
    }
  }
}

// ============================================
// API Gateway
// ============================================
class APIGateway {
  constructor(config = {}) {
    this.config = {
      port: config.port || 3000,
      host: config.host || '0.0.0.0',
      defaultUpstream: config.defaultUpstream || null,
      routes: config.routes || [],
      pluginDir: config.pluginDir || './plugins',
      pluginConfigs: config.pluginConfigs || [],
      envPlugins: config.envPlugins || [],
      inlinePlugins: config.inlinePlugins || [],
      adminEnabled: config.adminEnabled !== false,
      adminPath: config.adminPath || '/__admin',
      requestTimeout: config.requestTimeout || 30000,
      ...config
    };

    this.pluginManager = new PluginManager();
    this.server = null;
    this.routes = new Map();

    // Register routes
    for (const route of this.config.routes) {
      this.addRoute(route);
    }
  }

  // Add a route
  addRoute(route) {
    const key = `${route.method || 'ALL'}:${route.path}`;
    this.routes.set(key, route);
    console.log(`[Gateway] Route registered: ${key} -> ${route.upstream || 'handler'}`);
  }

  // Match a route
  matchRoute(method, reqPath) {
    // Exact match first
    let route = this.routes.get(`${method}:${reqPath}`) || this.routes.get(`ALL:${reqPath}`);
    if (route) return route;

    // Prefix matching
    for (const [key, rt] of this.routes) {
      const [routeMethod, routePath] = key.split(':');
      if ((routeMethod === 'ALL' || routeMethod === method) && reqPath.startsWith(routePath)) {
        return rt;
      }
    }

    // Pattern matching with simple wildcards
    for (const [key, rt] of this.routes) {
      const [routeMethod, routePath] = key.split(':');
      if (routeMethod !== 'ALL' && routeMethod !== method) continue;

      const pattern = routePath.replace(/\*/g, '.*').replace(/:[^/]+/g, '[^/]+');
      const regex = new RegExp(`^${pattern}$`);
      if (regex.test(reqPath)) {
        return rt;
      }
    }

    return null;
  }

  // Read request body
  readBody(req) {
    return new Promise((resolve, reject) => {
      const chunks = [];
      req.on('data', chunk => chunks.push(chunk));
      req.on('end', () => resolve(Buffer.concat(chunks)));
      req.on('error', reject);
    });
  }

  // Proxy request to upstream
  proxyToUpstream(context) {
    return new Promise((resolve, reject) => {
      const upstream = url.parse(context.upstream);
      const isHttps = upstream.protocol === 'https:';
      const transport = isHttps ? https : http;

      const options = {
        hostname: upstream.hostname,
        port: upstream.port || (isHttps ? 443 : 80),
        path: context.path + (context.parsedUrl.search || ''),
        method: context.method,
        headers: {
          ...context.headers,
          host: upstream.host
        },
        timeout: this.config.requestTimeout
      };

      const proxyReq = transport.request(options, (proxyRes) => {
        context.upstreamResponse = {
          statusCode: proxyRes.statusCode,
          headers: proxyRes.headers
        };

        const chunks = [];
        proxyRes.on('data', chunk => chunks.push(chunk));
        proxyRes.on('end', () => {
          const body = Buffer.concat(chunks);
          context.responseStatusCode = proxyRes.statusCode;
          context.responseHeaders = { ...context.responseHeaders, ...proxyRes.headers };
          context.responseBody = body;
          resolve(context);
        });
      });

      proxyReq.on('error', (err) => {
        reject(err);
      });

      proxyReq.on('timeout', () => {
        proxyReq.destroy();
        reject(new Error('Upstream request timeout'));
      });

      if (context.body) {
        proxyReq.write(context.body);
      }

      proxyReq.end();
    });
  }

  // Handle admin requests
  handleAdmin(context) {
    const adminPath = this.config.adminPath;
    const subPath = context.path.substring(adminPath.length);

    switch (subPath) {
      case '/plugins':
        if (context.method === 'GET') {
          context.setResponse(200, {
            plugins: this.pluginManager.listPlugins()
          }, { 'Content-Type': 'application/json' });
        } else if (context.method === 'POST') {
          // Load a new plugin dynamically
          try {
            const bodyStr = context.body ? context.body.toString() : '{}';
            const payload = JSON.parse(bodyStr);

            if (payload.file) {
              this.pluginManager.loadPluginFromFile(payload.file);
            } else if (payload.code) {
              this.pluginManager.loadPluginFromCode(payload.code, payload.name);
            } else if (payload.env) {
              this.pluginManager.loadPluginFromEnv(payload.env);
            } else {
              context.setResponse(400, { error: 'Provide "file", "code", or "env" field' }, { 'Content-Type': 'application/json' });
              return;
            }

            context.setResponse(201, {
              message: 'Plugin loaded successfully',
              plugins: this.pluginManager.listPlugins()
            }, { 'Content-Type': 'application/json' });
          } catch (err) {
            context.setResponse(500, { error: err.message }, { 'Content-Type': 'application/json' });
          }
        } else if (context.method === 'DELETE') {
          try {
            const bodyStr = context.body ? context.body.toString() : '{}';
            const payload = JSON.parse(bodyStr);
            if (payload.name) {
              this.pluginManager.unregisterPlugin(payload.name);
              context.setResponse(200, { message: `Plugin "${payload.name}" unloaded` }, { 'Content-Type': 'application/json' });
            } else {
              context.setResponse(400, { error: 'Provide "name" field' }, { 'Content-Type': 'application/json' });
            }
          } catch (err) {
            context.setResponse(500, { error: err.message }, { 'Content-Type': 'application/json' });
          }
        }
        break;

      case '/routes':
        if (context.method === 'GET') {
          const routeList = [];
          for (const [key, rt] of this.routes) {
            routeList.push({ key, ...rt });
          }
          context.setResponse(200, { routes: routeList }, { 'Content-Type': 'application/json' });
        } else if (context.method === 'POST') {
          try {
            const bodyStr = context.body ? context.body.toString() : '{}';
            const route = JSON.parse(bodyStr);
            this.addRoute(route);
            context.setResponse(201, { message: 'Route added' }, { 'Content-Type': 'application/json' });
          } catch (err) {
            context.setResponse(500, { error: err.message }, { 'Content-Type': 'application/json' });
          }
        }
        break;

      case '/health':
        context.setResponse(200, {
          status: 'healthy',
          uptime: process.uptime(),
          memory: process.memoryUsage(),
          plugins: this.pluginManager.listPlugins().length,
          routes: this.routes.size
        }, { 'Content-Type': 'application/json' });
        break;

      default:
        context.setResponse(200, {
          gateway: 'API Gateway',
          endpoints: [
            `${adminPath}/plugins - GET/POST/DELETE`,
            `${adminPath}/routes - GET/POST`,
            `${adminPath}/health - GET`
          ]
        }, { 'Content-Type': 'application/json' });
    }
  }

  // Main request handler
  async handleRequest(req, res) {
    const context = new GatewayContext(req, res);

    try {
      // Read body for non-GET requests
      if (req.method !== 'GET' && req.method !== 'HEAD') {
        context.body = await this.readBody(req);
      }

      // Check admin routes
      if (this.config.adminEnabled && context.path.startsWith(this.config.adminPath)) {
        this.handleAdmin(context);
        context.sendResponse();
        return;
      }

      // Execute onRequest hooks
      await this.pluginManager.executeHook('onRequest', context);

      if (context._stopped || context._responseSent) {
        if (!context._responseSent) context.sendResponse();
        return;
      }

      // Route matching
      const route = this.matchRoute(context.method, context.path);

      if (route) {
        context.setUpstream(route.upstream || this.config.defaultUpstream);
        context.metadata.route = route;

        // Execute route-specific handler if provided
        if (typeof route.handler === 'function') {
          await route.handler(context);
        }
      } else if (this.config.defaultUpstream) {
        context.setUpstream(this.config.defaultUpstream);
      }

      // Proxy to upstream if set and response not already determined
      if (context.upstream && !context.responseBody && !context._stopped) {
        try {
          await this.proxyToUpstream(context);
        } catch (proxyErr) {
          console.error(`[Gateway] Proxy error: ${proxyErr.message}`);
          context.setResponse(502, {
            error: 'Bad Gateway',
            message: proxyErr.message
          }, { 'Content-Type': 'application/json' });
        }
      } else if (!context.upstream && !context.responseBody) {
        context.setResponse(404, {
          error: 'Not Found',
          message: `No route found for ${context.method} ${context.path}`
        }, { 'Content-Type': 'application/json' });
      }

      // Execute onResponse hooks
      await this.pluginManager.executeHook('onResponse', context);

      // Send the final response
      if (!context._responseSent) {
        context.sendResponse();
      }

    } catch (err) {
      console.error(`[Gateway] Request error:`, err);

      // Execute onError hooks
      context.error = err;
      await this.pluginManager.executeHook('onError', context);

      if (!context._responseSent) {
        context.setResponse(500, {
          error: 'Internal Server Error',
          message: err.message,
          requestId: context.requestId
        }, { 'Content-Type': 'application/json' });
        context.sendResponse();
      }
    }
  }

  // Load plugins from configuration
  async loadPlugins() {
    // Load plugins from plugin directory
    if (this.config.pluginDir && fs.existsSync(this.config.pluginDir)) {
      const pluginFiles = fs.readdirSync(this.config.pluginDir).filter(f => f.endsWith('.js'));
      for (const file of pluginFiles) {
        try {
          this.pluginManager.loadPluginFromFile(path.join(this.config.pluginDir, file));
        } catch (err) {
          console.error(`[Gateway] Failed to load plugin ${file}:`, err.message);
        }
      }
    }

    // Load plugins from config file references
    for (const pluginConfig of this.config.pluginConfigs) {
      try {
        if (pluginConfig.file) {
          this.pluginManager.loadPluginFromFile(pluginConfig.file);
        } else if (pluginConfig.code) {
          this.pluginManager.loadPluginFromCode(pluginConfig.code, pluginConfig.name);
        }
      } catch (err) {
        console.error(`[Gateway] Failed to load plugin config:`, err.message);
      }
    }

    // Load plugins from environment variables
    for (const envVar of this.config.envPlugins) {
      try {
        this.pluginManager.loadPluginFromEnv(envVar);
      } catch (err) {
        console.error(`[Gateway] Failed to load env plugin ${envVar}:`, err.message);
      }
    }

    // Load inline plugins
    for (const inlinePlugin of this.config.inlinePlugins) {
      try {
        this.pluginManager.loadPluginFromCode(inlinePlugin.code, inlinePlugin.name);
      } catch (err) {
        console.error(`[Gateway] Failed to load inline plugin:`, err.message);
      }
    }
  }

  // Start the gateway
  async start() {
    // Load all plugins
    await this.loadPlugins();

    // Execute startup hooks
    await this.pluginManager.executeHook('onStartup', { gateway: this });

    // Create HTTP server
    this.server = http.createServer((req, res) => this.handleRequest(req, res));

    return new Promise((resolve) => {
      this.server.listen(this.config.port, this.config.host, () => {
        console.log(`[Gateway] API Gateway running on http://${this.config.host}:${this.config.port}`);
        console.log(`[Gateway] Admin panel: http://${this.config.host}:${this.config.port}${this.config.adminPath}`);
        console.log(`[Gateway] Loaded plugins: ${this.pluginManager.plugins.size}`);
        console.log(`[Gateway] Registered routes: ${this.routes.size}`);
        resolve(this);
      });
    });
  }

  // Stop the gateway
  async stop() {
    await this.pluginManager.executeHook('onShutdown', { gateway: this });

    if (this.server) {
      return new Promise((resolve) => {
        this.server.close(() => {
          console.log('[Gateway] Server stopped');
          resolve();
        });
      });
    }
  }
}

// ============================================
// Configuration Loader
// ============================================
function loadConfig(configPath) {
  if (configPath && fs.existsSync(configPath)) {
    const raw = fs.readFileSync(configPath, 'utf8');
    return JSON.parse(raw);
  }

  // Default configuration
  return {
    port: parseInt(process.env.GATEWAY_PORT) || 3000,
    host: process.env.GATEWAY_HOST || '0.0.0.0',
    defaultUpstream: process.env.DEFAULT_UPSTREAM || null,
    pluginDir: process.env.PLUGIN_DIR || './plugins',
    adminEnabled: process.env.ADMIN_ENABLED !== 'false',
    adminPath: process.env.ADMIN_PATH || '/__admin',
    requestTimeout: parseInt(process.env.REQUEST_TIMEOUT) || 30000,
    routes: [],
    pluginConfigs: [],
    envPlugins: process.env.GATEWAY_PLUGINS ? process.env.GATEWAY_PLUGINS.split(',') : [],
    inlinePlugins: []
  };
}

